sqlServer.code:
-- STRING_SPLIT: split a delimited string into a table of values (SQL Server 2016+)
DECLARE @csv NVARCHAR(200) = N'apple,banana,cherry,date';

SELECT value AS fruit
FROM STRING_SPLIT(@csv, ',');
-- Returns rows: apple | banana | cherry | date

-- Use in a JOIN or WHERE clause
SELECT p.product_name
FROM products p
JOIN STRING_SPLIT(N'apple,banana,cherry', ',') s
  ON p.product_name = s.value;

-- OPENJSON: parse a JSON array into rows
DECLARE @json NVARCHAR(200) = N'["apple","banana","cherry"]';

SELECT [value] AS fruit
FROM OPENJSON(@json);
-- Returns rows: apple | banana | cherry

postgres.code:
-- STRING_TO_ARRAY + UNNEST: split a delimited string into rows
SELECT unnest(string_to_array('apple,banana,cherry,date', ',')) AS fruit;
-- Returns rows: apple | banana | cherry | date

-- WITH ORDINALITY: preserve position/order
SELECT fruit, ordinality AS position
FROM unnest(string_to_array('apple,banana,cherry,date', ','))
     WITH ORDINALITY AS t(fruit, ordinality);

-- REGEXP_SPLIT_TO_TABLE: split using a POSIX regex delimiter
SELECT regexp_split_to_table('apple, banana,  cherry', '\s*,\s*') AS fruit;
-- Trims surrounding whitespace around the comma

-- REGEXP_SPLIT_TO_ARRAY: split into an array instead of rows
SELECT regexp_split_to_array('apple,banana,cherry', ',') AS fruit_array;
-- Returns: {apple,banana,cherry}

-- jsonb_array_elements_text: shred a JSON array into rows (equivalent to OPENJSON)
SELECT value AS fruit
FROM jsonb_array_elements_text('["apple","banana","cherry"]'::jsonb);
